#!/usr/bin/env python3
"""Parse pytest JSON or JUnit XML reports and extract failure details for the Fix Agent."""

import argparse
import json
import sys
from datetime import datetime, timezone
from pathlib import Path
from xml.etree import ElementTree


def parse_pytest_json(path: Path) -> dict:
    """Parse a pytest JSON report (generated by pytest-json-report or --json-report)."""
    with open(path, "r") as f:
        data = json.load(f)

    summary = data.get("summary", {})
    total = summary.get("total", 0)
    passed = summary.get("passed", 0)
    failed = summary.get("failed", 0)
    errors = summary.get("errors", 0)

    failed_tests = []
    for test in data.get("tests", []):
        if test.get("outcome") in ("failed", "error"):
            nodeid = test.get("nodeid", "")
            file = ""
            line = 0
            error_msg = ""
            traceback = ""

            # Extract file and line from nodeid
            if "::" in nodeid:
                file_part = nodeid.split("::")[0]
                file = file_part.split(":")[0] if ":" in file_part else file_part
            else:
                file = nodeid

            # Try lineno from test root
            line = test.get("lineno", 0)

            # Extract error from longrepr (most reliable)
            longrepr = test.get("longrepr", "")
            if longrepr:
                # Parse first meaningful error line
                lines = longrepr.split("\n")
                for l in lines:
                    if l.startswith("E   ") or l.startswith("E "):
                        error_msg = l[4:] if l.startswith("E   ") else l[2:]
                        break
                if not error_msg:
                    for l in lines:
                        if "Error" in l or "Exception" in l or "Failed" in l:
                            error_msg = l.strip()
                            break
                traceback = longrepr

            # Fallback: extract from call dict
            call = test.get("call", {})
            if not error_msg and call.get("crash"):
                crash = call["crash"]
                error_msg = crash.get("message", "")
                if crash.get("path"):
                    file = crash["path"]
                if crash.get("lineno"):
                    line = crash["lineno"]

            if not traceback and call.get("traceback"):
                tb_lines = []
                for entry in call["traceback"]:
                    tb_lines.append(
                        f'  File "{entry.get("path", "")}", line {entry.get("lineno", 0)}, in {entry.get("message", "")}'
                    )
                traceback = "\n".join(tb_lines)

            failed_tests.append(
                {
                    "test_name": nodeid,
                    "file": file,
                    "line": line,
                    "error": error_msg,
                    "traceback": traceback,
                }
            )

    return {
        "summary": {
            "total": total,
            "passed": passed,
            "failed": failed,
            "errors": errors,
        },
        "failed_tests": failed_tests,
        "all_passed": failed == 0 and errors == 0,
    }


def parse_junit_xml(path: Path) -> dict:
    """Parse a JUnit XML report."""
    tree = ElementTree.parse(path)
    root = tree.getroot()

    total = 0
    failed = 0
    errors = 0

    failed_tests = []

    for testsuite in root.iter("testsuite"):
        total += int(testsuite.get("tests", 0))
        failed += int(testsuite.get("failures", 0))
        errors += int(testsuite.get("errors", 0))

        for testcase in testsuite.iter("testcase"):
            failure = testcase.find("failure")
            error_elem = testcase.find("error")
            if failure is not None or error_elem is not None:
                elem = failure if failure is not None else error_elem
                classname = testcase.get("classname", "")
                testname = testcase.get("name", "")
                nodeid = f"{classname}::{testname}" if classname else testname

                file = testcase.get("file", classname.split(".")[0] if classname else "")
                line = int(testcase.get("line", 0))
                message = elem.get("message", "")
                text = elem.text or ""

                # Extract short error message from text if message is empty
                error_msg = message
                if not error_msg and text:
                    lines = text.strip().split("\n")
                    error_msg = lines[0] if lines else ""

                failed_tests.append(
                    {
                        "test_name": nodeid,
                        "file": file,
                        "line": line,
                        "error": error_msg,
                        "traceback": text,
                    }
                )

    passed = total - failed - errors

    return {
        "summary": {
            "total": total,
            "passed": max(passed, 0),
            "failed": failed,
            "errors": errors,
        },
        "failed_tests": failed_tests,
        "all_passed": failed == 0 and errors == 0,
    }


def main():
    parser = argparse.ArgumentParser(
        description="Parse test results and extract failure details for the Fix Agent."
    )
    parser.add_argument(
        "--input",
        required=True,
        help="Path to pytest JSON report or JUnit XML report",
    )
    parser.add_argument(
        "--output",
        required=True,
        help="Path to write the parsed failures JSON",
    )
    args = parser.parse_args()

    input_path = Path(args.input)
    output_path = Path(args.output)

    if not input_path.exists():
        print(f"Error: input file not found: {input_path}", file=sys.stderr)
        sys.exit(1)

    # Detect format by extension
    if input_path.suffix.lower() == ".xml":
        result = parse_junit_xml(input_path)
    else:
        result = parse_pytest_json(input_path)

    # Build output
    output = {
        "generated_at": datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%S"),
        "input_file": str(input_path),
        **result,
    }

    # Ensure output directory exists
    output_path.parent.mkdir(parents=True, exist_ok=True)

    with open(output_path, "w") as f:
        json.dump(output, f, indent=2)

    print(f"Parsed {input_path} -> {output_path}")
    if result["failed_tests"]:
        print(f"  {len(result['failed_tests'])} failure(s) found")
    else:
        print("  All tests passed")


if __name__ == "__main__":
    main()
